/// <summary>
///    The <c>ETGPurchRegisterReportUIBuilder</c> class is the user interface builder class for the associated SQL
///    Server Reporting Services (SSRS) report.
/// </summary>
public class ETGPurchRegisterReportUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGPurchRegisterReportContract  contract;

}

Method.Source:
/// <summary>
///    building all parameters
/// </summary>
public void build()
{
    contract = this.dataContractObject();

    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmFromDate), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmToDate), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmFinancialDimSet), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmIsDetailReport), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewConfigId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventSizeId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventColorId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventStyleId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventSiteId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventLocationId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewWMSLocationId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewLicensePlateId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventStatus), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventBatchId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventSerialId), contract);
    this.addDialogField(methodStr(ETGPurchRegisterReportContract, parmViewInventOwnerId_RU), contract);
}

/// <summary>
///    creating dialog fields
/// </summary>
public void postBuild()
{
    DialogField     finDimSet;

    super();

    finDimSet = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGPurchRegisterReportContract, parmFinancialDimSet));
    finDimSet.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGPurchRegisterReportUIBuilder, finDimSetLookup), this);
}

/// <summary>
///    creating dimension sets lookup
/// </summary>
/// <param name = "_formStringControl">form string control</param>
public void finDimSetLookup(FormStringControl   _formStringControl)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tablenum(DimensionHierarchy), _formStringControl);

    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Name));
    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Description));

    qbds = query.addDataSource(tableNum(DimensionHierarchy));
    qbds.addRange(fieldNum(DimensionHierarchy, StructureType)).value(queryValue(DimensionHierarchyType::Focus));
    qbds.addRange(fieldNum(DimensionHierarchy, IsSystemGenerated)).value(queryValue(NoYes::No));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
